'use client'

import { useState } from 'react'
import { useAuth } from '@/lib/auth-context'
import { CircleHelp, Plus, Trash2 } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'

interface WorkoutSession {
  id: string
  type: 'cardio' | 'strength' | 'flexibility' | 'sports'
  intensity: 'low' | 'medium' | 'high'
  name: string
  duration: number
  caloriesBurned: number
  caloriesSource: 'estimated' | 'manual'
  distanceKm?: number
  notes?: string
  date: string
}

const metValues: Record<WorkoutSession['type'], Record<WorkoutSession['intensity'], number>> = {
  cardio: { low: 6, medium: 8, high: 10 },
  strength: { low: 3.5, medium: 5, high: 6 },
  flexibility: { low: 2.5, medium: 3, high: 3.5 },
  sports: { low: 5, medium: 7, high: 9 },
}

const workoutTypeLabels: Record<WorkoutSession['type'], string> = {
  cardio: 'Cardio',
  strength: 'Strength',
  flexibility: 'Flexibility',
  sports: 'Sports',
}

const intensityLabels: Record<WorkoutSession['intensity'], string> = {
  low: 'Low',
  medium: 'Medium',
  high: 'High',
}

const estimateCalories = (
  type: WorkoutSession['type'],
  intensity: WorkoutSession['intensity'],
  duration: number,
  userWeight: number
) => {
  if (!duration) return 0
  const weight = userWeight > 0 ? userWeight : 70
  const met = metValues[type][intensity]
  return Math.round((met * 3.5 * weight * duration) / 200)
}

export default function TrainingPage() {
  const { user } = useAuth()
  const [workouts, setWorkouts] = useState<WorkoutSession[]>([
    {
      id: '1',
      type: 'cardio',
      intensity: 'medium',
      name: '5K Run',
      duration: 30,
      caloriesBurned: 350,
      caloriesSource: 'manual',
      distanceKm: 5,
      date: new Date().toISOString().split('T')[0],
    },
    {
      id: '2',
      type: 'strength',
      intensity: 'high',
      name: 'Upper Body Workout',
      duration: 45,
      caloriesBurned: 280,
      caloriesSource: 'manual',
      date: new Date(Date.now() - 86400000).toISOString().split('T')[0],
    },
  ])
  const [showForm, setShowForm] = useState(false)
  const [formData, setFormData] = useState({
    type: 'cardio' as const,
    intensity: 'medium' as const,
    name: '',
    duration: 0,
    caloriesBurned: '',
    distanceKm: '',
    notes: '',
  })

  const estimatedCalories = estimateCalories(
    formData.type,
    formData.intensity,
    formData.duration,
    user?.weight || 0
  )

  const addWorkout = () => {
    if (!formData.name || formData.duration === 0) {
      alert('Please fill in all fields')
      return
    }

    const finalCalories =
      Number(formData.caloriesBurned) > 0 ? Number(formData.caloriesBurned) : estimatedCalories
    const caloriesSource: WorkoutSession['caloriesSource'] =
      Number(formData.caloriesBurned) > 0 ? 'manual' : 'estimated'

    const newWorkout: WorkoutSession = {
      id: Math.random().toString(36).substr(2, 9),
      type: formData.type,
      intensity: formData.intensity,
      name: formData.name,
      duration: formData.duration,
      caloriesBurned: finalCalories,
      caloriesSource,
      distanceKm:
        formData.type === 'cardio' && Number(formData.distanceKm) > 0
          ? Number(formData.distanceKm)
          : undefined,
      notes: formData.notes || undefined,
      date: new Date().toISOString().split('T')[0],
    }

    setWorkouts([newWorkout, ...workouts])
    setFormData({
      type: 'cardio',
      intensity: 'medium',
      name: '',
      duration: 0,
      caloriesBurned: '',
      distanceKm: '',
      notes: '',
    })
    setShowForm(false)
  }

  const deleteWorkout = (id: string) => {
    setWorkouts(workouts.filter(w => w.id !== id))
  }

  const totalCalories = workouts.reduce((sum, w) => sum + w.caloriesBurned, 0)
  const totalMinutes = workouts.reduce((sum, w) => sum + w.duration, 0)

  if (!user) return null

  return (
    <div className="p-8 max-w-4xl mx-auto">
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-3xl font-bold text-foreground">Training Log</h1>
        <Button
          onClick={() => setShowForm(!showForm)}
          className="flex items-center gap-2"
        >
          <Plus size={20} /> New Workout
        </Button>
      </div>

      {/* Stats */}
      <div className="grid md:grid-cols-3 gap-6 mb-8">
        <div className="bg-card rounded-lg border border-border p-6">
          <p className="text-muted-foreground text-sm mb-2">Total Workouts</p>
          <p className="text-3xl font-bold text-foreground">{workouts.length}</p>
        </div>
        <div className="bg-card rounded-lg border border-border p-6">
          <p className="text-muted-foreground text-sm mb-2">Total Minutes</p>
          <p className="text-3xl font-bold text-foreground">{totalMinutes}</p>
        </div>
        <div className="bg-card rounded-lg border border-border p-6">
          <p className="text-muted-foreground text-sm mb-2">Total Calories Burned</p>
          <p className="text-3xl font-bold text-foreground">{totalCalories}</p>
        </div>
      </div>

      {/* Add Workout Form */}
      {showForm && (
        <div className="bg-card rounded-lg border border-border p-6 mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Log a Workout</h3>
          <div className="space-y-4">
            <div className="grid md:grid-cols-3 gap-4">
              <div>
                <Label className="block mb-2">Type</Label>
                <Select
                  value={formData.type}
                  onValueChange={value =>
                    setFormData({ ...formData, type: value as WorkoutSession['type'] })
                  }
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="cardio">Cardio</SelectItem>
                    <SelectItem value="strength">Strength</SelectItem>
                    <SelectItem value="flexibility">Flexibility</SelectItem>
                    <SelectItem value="sports">Sports</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label className="block mb-2">Intensity</Label>
                <Select
                  value={formData.intensity}
                  onValueChange={value =>
                    setFormData({ ...formData, intensity: value as WorkoutSession['intensity'] })
                  }
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="low">Low</SelectItem>
                    <SelectItem value="medium">Medium</SelectItem>
                    <SelectItem value="high">High</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label className="block mb-2">Workout Name</Label>
                <Input
                  type="text"
                  placeholder="e.g., 5K Run"
                  value={formData.name}
                  onChange={e => setFormData({ ...formData, name: e.target.value })}
                />
              </div>
            </div>
            <div className="grid md:grid-cols-3 gap-4">
              <div>
                <Label className="block mb-2">Duration (minutes)</Label>
                <Input
                  type="number"
                  value={formData.duration}
                  onChange={e => setFormData({ ...formData, duration: parseInt(e.target.value) || 0 })}
                />
              </div>
              <div>
                <Label className="block mb-2">Distance (km) {formData.type !== 'cardio' ? '(cardio only)' : ''}</Label>
                <Input
                  type="number"
                  step="0.1"
                  disabled={formData.type !== 'cardio'}
                  value={formData.distanceKm}
                  placeholder={formData.type === 'cardio' ? 'e.g., 5' : 'Not required'}
                  onChange={e => setFormData({ ...formData, distanceKm: e.target.value })}
                />
              </div>
              <div>
                <Label className="block mb-2">Calories Burned (optional)</Label>
                <Input
                  type="number"
                  value={formData.caloriesBurned}
                  placeholder={`Auto estimate: ${estimatedCalories} kcal`}
                  onChange={e => setFormData({ ...formData, caloriesBurned: e.target.value })}
                />
              </div>
              <div className="bg-muted rounded-lg border border-border px-4 py-3">
                <p className="text-xs text-muted-foreground mb-1">Estimated calories</p>
                <p className="text-xl font-bold text-foreground">{estimatedCalories} kcal</p>
                <p className="text-xs text-muted-foreground mt-1">
                  Based on {workoutTypeLabels[formData.type]}, {intensityLabels[formData.intensity]} intensity,
                  {` ${formData.duration || 0}`} min and your weight ({user?.weight || 70} kg)
                </p>
                <p className="text-xs text-muted-foreground mt-2 inline-flex items-center gap-1">
                  <CircleHelp size={12} />
                  Estimation only, real calories may vary by metabolism and effort.
                </p>
              </div>
            </div>
            <div>
              <Label className="block mb-2">Notes (optional)</Label>
              <Input
                type="text"
                placeholder="e.g., Felt strong, slight knee discomfort..."
                value={formData.notes}
                onChange={e => setFormData({ ...formData, notes: e.target.value })}
              />
            </div>
            <div className="flex gap-4">
              <Button
                onClick={addWorkout}
              >
                Add Workout
              </Button>
              <Button
                onClick={() => setShowForm(false)}
                variant="outline"
              >
                Cancel
              </Button>
            </div>
          </div>
        </div>
      )}

      {/* Workout List */}
      <div className="space-y-4">
        {workouts.length === 0 ? (
          <div className="text-center py-12 bg-card rounded-lg border border-border">
            <p className="text-muted-foreground text-lg">No workouts logged yet</p>
            <p className="text-muted-foreground text-sm">Start by logging your first workout!</p>
          </div>
        ) : (
          workouts.map(workout => (
            <div key={workout.id} className="bg-card rounded-lg border border-border p-6 flex justify-between items-center">
              <div className="flex-1">
                <h3 className="text-lg font-bold text-foreground mb-1">{workout.name}</h3>
                <div className="flex gap-6 text-sm text-muted-foreground">
                  <span>Type: <strong className="text-foreground">{workoutTypeLabels[workout.type]}</strong></span>
                  <span>Intensity: <strong className="text-foreground">{intensityLabels[workout.intensity]}</strong></span>
                  <span>Duration: <strong className="text-foreground">{workout.duration} min</strong></span>
                  {typeof workout.distanceKm === 'number' && (
                    <span>Distance: <strong className="text-foreground">{workout.distanceKm} km</strong></span>
                  )}
                  <span>
                    Calories: <strong className="text-foreground">{workout.caloriesBurned}</strong>{' '}
                    <span
                      className={`text-[10px] uppercase tracking-wide px-2 py-0.5 rounded-full border ${
                        workout.caloriesSource === 'manual'
                          ? 'border-emerald-300 text-emerald-600 bg-emerald-50'
                          : 'border-amber-300 text-amber-700 bg-amber-50'
                      }`}
                      title={
                        workout.caloriesSource === 'manual'
                          ? 'Calories entered manually by user'
                          : 'Calories estimated from type, intensity, duration and weight'
                      }
                    >
                      {workout.caloriesSource}
                    </span>
                  </span>
                  <span>Date: <strong className="text-foreground">{workout.date}</strong></span>
                </div>
                {workout.notes && (
                  <p className="text-sm text-muted-foreground mt-2 italic">Note: {workout.notes}</p>
                )}
              </div>
              <button
                onClick={() => deleteWorkout(workout.id)}
                className="p-2 text-destructive hover:bg-red-50 rounded-lg transition"
              >
                <Trash2 size={20} />
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  )
}
